// The synthetic ensures has the shape `H ==> det_set_io_mapping_equal(...)`,
// where H is the big conjunction of the two original-call ensures (one for
// `post1_self_` and one for `post2_self_`).  Because H is the *antecedent* of
// an implication, none of its conjuncts (e.g. `post1_self_.page_array.wf()`)
// are available as body-level hypotheses — they only enter the SMT context
// when Verus discharges the ensures at function exit.  That is why the
// previous attempt's unconditional `assert(post1_self_.page_array@.len() ==
// NUM_PAGES as int)` failed: there was no path through the body on which
// `post1_self_.page_array.wf()` was known.
//
// The fix is to wrap the proof inside `if H_relevant { ... }`.  Anything we
// assert inside the branch is recorded by Verus as
// `H_relevant ==> assertion`, which is exactly the form needed to discharge
// the synthetic ensures at exit (since H trivially implies H_relevant).
//
// Inside the branch we have the page_array-related conjuncts of H as a
// path condition; we use them to prove `post1_self_.page_array@ ==
// post2_self_.page_array@` via the standard "pointwise + `=~=`" pattern.
// The remaining `det_set_io_mapping_equal` conjuncts (`free_pages_*`,
// `allocated_pages_*`, `mapped_pages_*`, `page_perms_*`, `container_map_*`)
// each follow from two equalities of the form `post1.X == pre.X` and
// `post2.X == pre.X` already in H — that gives `post1.X == post2.X` by
// transitivity, hence `post1.X@ == post2.X@` (and `=~=` for sets/maps).
// Those Verus discharges itself once H is in scope at the ensures check.

if post1_self_.page_array.wf()
    && post2_self_.page_array.wf()
    && (forall|i: int|
            0 <= i < NUM_PAGES && i != index ==>
                post1_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && (forall|i: int|
            0 <= i < NUM_PAGES && i != index ==>
                post2_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && post1_self_.page_array@[index as int].addr
        =~= pre_self_.page_array@[index as int].addr
    && post2_self_.page_array@[index as int].addr
        =~= pre_self_.page_array@[index as int].addr
    && post1_self_.page_array@[index as int].state
        =~= pre_self_.page_array@[index as int].state
    && post2_self_.page_array@[index as int].state
        =~= pre_self_.page_array@[index as int].state
    && post1_self_.page_array@[index as int].is_io_page
        =~= pre_self_.page_array@[index as int].is_io_page
    && post2_self_.page_array@[index as int].is_io_page
        =~= pre_self_.page_array@[index as int].is_io_page
    && post1_self_.page_array@[index as int].rev_pointer
        =~= pre_self_.page_array@[index as int].rev_pointer
    && post2_self_.page_array@[index as int].rev_pointer
        =~= pre_self_.page_array@[index as int].rev_pointer
    && post1_self_.page_array@[index as int].ref_count
        =~= pre_self_.page_array@[index as int].ref_count
    && post2_self_.page_array@[index as int].ref_count
        =~= pre_self_.page_array@[index as int].ref_count
    && post1_self_.page_array@[index as int].owning_container
        =~= pre_self_.page_array@[index as int].owning_container
    && post2_self_.page_array@[index as int].owning_container
        =~= pre_self_.page_array@[index as int].owning_container
    && post1_self_.page_array@[index as int].mappings
        =~= pre_self_.page_array@[index as int].mappings
    && post2_self_.page_array@[index as int].mappings
        =~= pre_self_.page_array@[index as int].mappings
    && post1_self_.page_array@[index as int].io_mappings =~= io_mapping
    && post2_self_.page_array@[index as int].io_mappings =~= io_mapping
{
    // Pointwise equality of the two post-state page_array views.
    assert forall|i: int|
        0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] == post2_self_.page_array@[i]
    by {
        if i == index as int {
            // At i == index, every field of the Page is pinned to either
            // pre_self_.page_array@[index].* (seven fields) or to io_mapping
            // (just io_mappings), so post1 and post2 agree component-wise.
            assert(post1_self_.page_array@[i].addr
                == post2_self_.page_array@[i].addr);
            assert(post1_self_.page_array@[i].state
                == post2_self_.page_array@[i].state);
            assert(post1_self_.page_array@[i].is_io_page
                == post2_self_.page_array@[i].is_io_page);
            assert(post1_self_.page_array@[i].rev_pointer
                == post2_self_.page_array@[i].rev_pointer);
            assert(post1_self_.page_array@[i].ref_count
                == post2_self_.page_array@[i].ref_count);
            assert(post1_self_.page_array@[i].owning_container
                == post2_self_.page_array@[i].owning_container);
            assert(post1_self_.page_array@[i].mappings
                == post2_self_.page_array@[i].mappings);
            assert(post1_self_.page_array@[i].io_mappings
                == post2_self_.page_array@[i].io_mappings);
            assert(post1_self_.page_array@[i] =~= post2_self_.page_array@[i]);
        } else {
            // For i != index, both per-run foralls pin post*.page_array@[i]
            // to pre_self_.page_array@[i].  Mentioning both indexed views
            // here fires both foralls at the same `i`.
            assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
            assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        }
    }

    // Length equality of the two Seq views, from `.wf()` on both arrays.
    assert(post1_self_.page_array@.len() == NUM_PAGES);
    assert(post2_self_.page_array@.len() == NUM_PAGES);

    // Lift pointwise + length equality to Seq extensional equality.
    assert(post1_self_.page_array@ =~= post2_self_.page_array@);
}
